interface $STATE_TYPE {
	$STATE_FIELD: $FIELD_TYPE;
}

type $ACTION_TYPE =
	| { type: '$ACTION_A'; payload: $PAYLOAD_A_TYPE }
	| { type: '$ACTION_B'; payload: $PAYLOAD_B_TYPE };

function $REDUCER_NAME(state: $STATE_TYPE, action: $ACTION_TYPE): $STATE_TYPE {
	switch (action.type) {
		case '$ACTION_A':
			return { ...state, $STATE_FIELD: action.payload };
		case '$ACTION_B':
			return { ...state, $STATE_FIELD: action.payload };
		default:
			return state;
	}
}

const [$STATE, dispatch] = useReducer($REDUCER_NAME, $INITIAL_STATE);

