	$METHOD_NAME: ($PARAMS) => $METHOD_RETURN;
}

export function use$NAME($PARAMS): Use$NAMEReturn {
	const [$STATE, set$STATE_SETTER] = useState<$STATE_TYPE>($INITIAL);

	const $METHOD_NAME = useCallback(($PARAMS): $METHOD_RETURN => {
		$METHOD_BODY
	}, [$DEPENDENCIES]);

