interface $NAMEContextValue {
	$VALUE_FIELD: $VALUE_TYPE;
	$METHOD_NAME: ($PARAMS) => $METHOD_RETURN;
}

const $NAMEContext = createContext<$NAMEContextValue | undefined>(undefined);

export function $NAMEProvider({ children }: { children: React.ReactNode }): JSX.Element {
	const [$STATE, set$STATE_SETTER] = useState<$VALUE_TYPE>($INITIAL);

	const $METHOD_NAME = useCallback(($PARAMS): $METHOD_RETURN => {
		$METHOD_BODY
	}, [$DEPENDENCIES]);

	const value: $NAMEContextValue = useMemo(
		() => ({ $VALUE_FIELD: $STATE, $METHOD_NAME }),
		[$STATE, $METHOD_NAME]
	);

	return (
		<$NAMEContext.Provider value={value}>
			{children}
		</$NAMEContext.Provider>
	);
}

export function use$NAMEContext(): $NAMEContextValue {
	const context = useContext($NAMEContext);
	if (context === undefined) {
		throw new Error('use$NAMEContext must be used within a $NAMEProvider');
	}
	return context;
}

